            let filteredProducts = [];
            let simulatedQuery = "";

            if (!searchTerm) {
                displayResults(products, "Showing all products (empty search term)");
                return;
            }

            if (isVulnerableMode) {
                // --- VULNERABLE MODE: String Concatenation / Eval Simulation ---
                // Simulating a SQL query like: SELECT * FROM products WHERE name LIKE '%<searchTerm>%'
                // In JS, we can simulate this with eval or by constructing a dynamic filter.
                // For simplicity and direct vulnerability demo, we'll construct a filter expression.

                // This is a highly simplified and dangerous simulation of how SQL injection
                // manipulates the WHERE clause. In a real backend, this would be a database query.
                // Here, we're building a JS filter predicate dynamically.
                try {
                    // This is the core of the vulnerability simulation:
                    // The user input is directly inserted into a string that will be evaluated as code.
                    const filterExpression = `(product.name.toLowerCase().includes('${searchTerm.toLowerCase()}') || product.category.toLowerCase().includes('${searchTerm.toLowerCase()}'))`;
                    simulatedQuery = `Simulated JS Filter: products.filter(product => ${filterExpression})`;

                    // Using Function constructor to safely evaluate the filter expression in a controlled scope.
                    // THIS IS STILL DANGEROUS IF searchTerm COULD BREAK OUT OF THE PRODUCT SCOPE.
                    // For this demo, we assume 'product' is always defined within the function context.
                    const filterFunction = new Function('product', `return ${filterExpression}`);

                    filteredProducts = products.filter(product => {
                        try {
                            return filterFunction(product);
                        } catch (e) {
                            console.error("Error during vulnerable filter evaluation:", e);
                            return false; // Safely handle malformed expressions
                        }
                    });

                } catch (e) {
