                    console.error("Vulnerable search error:", e);
                    return;
                }

            } else {
                // --- SAFE MODE: Parameterized Query Simulation ---
                // Simulating a parameterized SQL query: SELECT * FROM products WHERE name LIKE ?
                // The user input is treated as a literal string.
                simulatedQuery = `Simulated JS Filter: products.filter(product => (product.name.toLowerCase().includes(searchTerm.toLowerCase()) || product.category.toLowerCase().includes(searchTerm.toLowerCase())))`;
                const lowerSearchTerm = searchTerm.toLowerCase();

                filteredProducts = products.filter(product =>
                    product.name.toLowerCase().includes(lowerSearchTerm) ||
                    product.category.toLowerCase().includes(lowerSearchTerm)
                );
            }

            displayResults(filteredProducts, simulatedQuery);
        }

        function displayResults(results, simulatedQuery) {
            resultsDiv.innerHTML = `<h3>Search Results:</h3>`;
            if (simulatedQuery) {
                resultsDiv.innerHTML += `<p style="font-size:0.9em; color:#6c757d;"><strong>${isVulnerableMode ? 'Vulnerable' : 'Safe'} Query:</strong> <code>${escapeHtml(simulatedQuery)}</code></p>`;
            }

            if (results.length === 0) {
                resultsDiv.innerHTML += `<p>No products found.</p>`;
            } else {
                results.forEach(product => {
                    resultsDiv.innerHTML += `
                        <div class="product-item">
                            <strong>${escapeHtml(product.name)}</strong>
                            <span>(ID: ${product.id}, Category: ${escapeHtml(product.category)}, Price: $${product.price})</span>
                        </div>
                    `;
                });
            }
        }

        // Helper function to escape HTML for displaying user input safely
        function escapeHtml(str) {
            const div = document.createElement('div');
            div.appendChild(document.createTextNode(str));
            return div.innerHTML;
        }

        // Initial display for all products
        displayResults(products, "Initial load: All products");
    </script>
</body>
