            filteredProducts = products.filter(p => p.name.toLowerCase().includes(searchTerm.toLowerCase()));

            document.getElementById('safeQueryDisplay').innerHTML = simulatedQuery;
            renderResults('safeResults', filteredProducts);
        }

        // --- Initial search on load (empty) ---
        performVulnerableSearch();
        performSafeSearch();
    </script>
