            { id: 5, name: "Monitor UltraWide 4K", category: "Electronics", price: 600 },
            { id: 6, name: "USB-C Hub Multiport", category: "Accessories", price: 40 },
            { id: 7, name: "Gaming Headset Surround", category: "Audio", price: 100 },
            { id: 8, name: "External SSD 1TB", category: "Storage", price: 180 },
            { id: 9, name: "Webcam Full HD", category: "Peripherals", price: 60 },
            { id: 10, name: "Smartwatch Sport", category: "Wearables", price: 250 },
            { id: 11, name: "Tablet Pro 11", category: "Electronics", price: 700 },
            { id: 12, name: "Coffee Maker Deluxe", category: "Home Goods", price: 120 }
        ];

        function displayResults(filteredProducts) {
            const resultsDiv = document.getElementById('searchResults');
            if (filteredProducts.length === 0) {
                resultsDiv.innerHTML = '<p class="no-results">No products found matching your criteria.</p>';
                return;
            }

            let tableHtml = '<table class="results-table"><thead><tr><th>ID</th><th>Name</th><th>Category</th><th>Price</th></tr></thead><tbody>';
            filteredProducts.forEach(product => {
                tableHtml += `<tr><td>${product.id}</td><td>${product.name}</td><td>${product.category}</td><td>$${product.price.toFixed(2)}</td></tr>`;
            });
            tableHtml += '</tbody></table>';
            resultsDiv.innerHTML = tableHtml;
        }

        function escapeHtml(str) {
            const div = document.createElement('div');
            div.appendChild(document.createTextNode(str));
            return div.innerHTML;
        }

        function searchVulnerable() {
            const input = document.getElementById('productSearchInput').value;
            let simulatedQuery = "";
            let filteredProducts = [];

            // --- VULNERABLE LOGIC START ---
            // Simulate a SQL query using string concatenation
            // In a real backend, this would be passed to a database
